import React, { createContext, useContext, useState, useEffect, useCallback } from 'react';
import api from '../utils/api';
import { useAuth } from './AuthContext';

// Features superadmin/admin always have access to
const ALL_FEATURES = [
  'dashboard', 'patients', 'doctors', 'appointments',
  'records', 'vitals', 'timeline', 'audit', 'profile', 'notifications',
];

const PermissionsContext = createContext();

export const PermissionsProvider = ({ children }) => {
  const { user } = useAuth();
  const [permissions, setPermissions] = useState([]);
  const [allRolePerms, setAllRolePerms] = useState([]); // superadmin view
  const [loading, setLoading] = useState(true);

  const isSuperAdmin = user?.role === 'superadmin';
  const isAdmin      = user?.role === 'admin';

  const fetchMyPermissions = useCallback(async () => {
    if (!user) { setPermissions([]); setLoading(false); return; }
    if (isSuperAdmin || isAdmin) {
      setPermissions(ALL_FEATURES);
      setLoading(false);
      return;
    }
    try {
      const res = await api.get(`/permissions/${user.role}`);
      setPermissions(res.data.permissions || []);
    } catch {
      setPermissions([]);
    } finally {
      setLoading(false);
    }
  }, [user, isSuperAdmin, isAdmin]);

  const fetchAllRolePerms = useCallback(async () => {
    if (!isSuperAdmin) return;
    try {
      const res = await api.get('/permissions');
      setAllRolePerms(res.data.permissions || []);
    } catch {
      setAllRolePerms([]);
    }
  }, [isSuperAdmin]);

  useEffect(() => {
    setLoading(true);
    fetchMyPermissions();
  }, [fetchMyPermissions]);

  useEffect(() => {
    fetchAllRolePerms();
  }, [fetchAllRolePerms]);

  // Check if current user can access a feature
  const can = (feature) => {
    if (isSuperAdmin || isAdmin) return true;
    return permissions.includes(feature);
  };

  // Update permissions for a role (superadmin only)
  const updateRolePermissions = async (role, newPerms) => {
    const res = await api.put(`/permissions/${role}`, { permissions: newPerms });
    setAllRolePerms((prev) =>
      prev.map((p) => (p.role === role ? { ...p, permissions: newPerms } : p))
    );
    return res.data;
  };

  return (
    <PermissionsContext.Provider value={{
      permissions,
      allRolePerms,
      allFeatures: ALL_FEATURES,
      loading,
      can,
      updateRolePermissions,
      refreshAllRolePerms: fetchAllRolePerms,
    }}>
      {children}
    </PermissionsContext.Provider>
  );
};

export const usePermissions = () => useContext(PermissionsContext);
